class Solution:
    def goodSubtreeSum(self, vals, par):
        MOD = 10**9 + 7
        n = len(vals)
        children = [[] for _ in range(n)]
        for i in range(1, n):
            children[par[i]].append(i)
        def mask_of(x):
            seen = 0
            while x:
                d = x % 10
                b = 1 << d
                if seen & b:
                    return -1
                seen |= b
                x //= 10
            return seen
        def subtree_nodes(u):
            stack = [u]
            out = []
            while stack:
                c = stack.pop()
                out.append(c)
                stack.extend(children[c])
            return out
        total = 0
        for u in range(n):
            items = []
            for node in subtree_nodes(u):
                m = mask_of(vals[node])
                if m != -1:
                    items.append((m, vals[node]))
            best = 0
            L = len(items)
            for sub in range(1 << L) if L <= 18 else []:
                used = 0
                s = 0
                ok = True
                for b in range(L):
                    if sub & (1 << b):
                        m, v = items[b]
                        if used & m:
                            ok = False
                            break
                        used |= m
                        s += v
                if ok and s > best:
                    best = s
            if L > 18:
                dp = [-1] * 1024
                dp[0] = 0
                for m, v in items:
                    cur = dp[:]
                    for usedmask in range(1024):
                        if dp[usedmask] >= 0 and (usedmask & m) == 0:
                            cand = dp[usedmask] + v
                            if cand > cur[usedmask | m]:
                                cur[usedmask | m] = cand
                    dp = cur
                best = max(x for x in dp if x >= 0)
            total = (total + best) % MOD
        return total

