            return seen
        order = []
        stack = [0]
        while stack:
            u = stack.pop()
            order.append(u)
            stack.extend(children[u])
        items_in_subtree = [None] * n
        total = 0
        for u in reversed(order):
            m = mask_of(vals[u])
