var goodSubtreeSum = function(vals, par) {
    const MOD = 1000000007n;
    const n = vals.length;
    const children = Array.from({length: n}, () => []);
    for (let i = 1; i < n; i++) children[par[i]].push(i);
    const maskOf = (x) => {
        let seen = 0;
        while (x > 0) {
            const d = x % 10;
            const b = 1 << d;
            if (seen & b) return -1;
            seen |= b;
            x = Math.floor(x / 10);
        }
        return seen;
    };
    const order = [];
    const stack = [0];
    while (stack.length) {
        const u = stack.pop();
        order.push(u);
        for (const c of children[u]) stack.push(c);
    }
    const itemsInSubtree = new Array(n).fill(null);
    let total = 0n;
    for (let oi = order.length - 1; oi >= 0; oi--) {
        const u = order[oi];
        const m = maskOf(vals[u]);
        const mine = [];
        if (m !== -1) mine.push([m, vals[u]]);
        for (const c of children[u]) {
            for (const it of itemsInSubtree[c]) mine.push(it);
            itemsInSubtree[c] = null;
        }
        itemsInSubtree[u] = mine;
        const dp = new Array(1024).fill(-1);
        dp[0] = 0;
        for (const [mm, vv] of mine) {
            const cur = dp.slice();
            for (let used = 0; used < 1024; used++) {
                if (dp[used] >= 0 && (used & mm) === 0) {
                    const cand = dp[used] + vv;
                    if (cand > cur[used | mm]) cur[used | mm] = cand;
                }
            }
            for (let i = 0; i < 1024; i++) dp[i] = cur[i];
        }
        let best = 0;
        for (const x of dp) if (x > best) best = x;
        total = (total + BigInt(best)) % MOD;
    }
    return Number(total);
};
